                                />
                                <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none rounded-full peer dark:bg-gray-700 peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all peer-checked:bg-amber-500"></div>
                            </label>
                        </div>
                    </SettingsGroup>

                    <SettingsGroup title="Danger Zone">
                        <SettingsRow icon={LogOut} label="Log Out" isDanger onClick={handleSignOut} />
                    </SettingsGroup>

                </div>
            </div>

            {/* MOBILE DRAWERS */}
            <MobileDrawer title="Edit Profile" isOpen={mobileSection === 'profile'} onClose={() => setMobileSection(null)}>
                <ProfileEditor
                    profileData={profileData}
                    setProfileData={setProfileData}
                    userEmail={userEmail}
                    onSave={handleSaveProfile}
                    isSaving={isSavingProfile}
                />
            </MobileDrawer>

            <MobileDrawer title="Model Parameters" isOpen={mobileSection === 'ai'} onClose={() => setMobileSection(null)}>
                <AIEditor
                    systemConfig={systemConfig}
                    setSystemConfig={setSystemConfig}
                    userEmail={userEmail}
                />
            </MobileDrawer>

            <AvatarSelectionModal
                isOpen={isAvatarModalOpen}
                onClose={() => setIsAvatarModalOpen(false)}
                onConfirm={handleUpdateAvatar}
                currentAvatarUrl={profileData.avatarUrl}
            />
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { createBrowserClient } from '@supabase/auth-helpers-nextjs';
import { Search, Plus, User, Shield, Trash2, Check, X, Mail, Lock, ShieldAlert } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { api } from '@/lib/api';

// Defined types matching Supabase structure
interface UserRole {
    id: string;
    email: string;
    role: 'admin' | 'super_admin'; // Using string union for roles
    is_admin: boolean; // Keep for backward compatibility if needed, but rely on 'role'
    created_at?: string;
}

export default function UsersPage() {
    const [users, setUsers] = useState<UserRole[]>([]);
    const [isLoading, setIsLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [isInviteModalOpen, setIsInviteModalOpen] = useState(false);

    // Permission State
    const [currentUserRole, setCurrentUserRole] = useState<'admin' | 'super_admin' | null>(null);

    const supabase = createBrowserClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
    );

    useEffect(() => {
        const init = async () => {
            await fetchCurrentUserRole();
            await fetchUsers();
        };
        init();
    }, []);

    const fetchCurrentUserRole = async () => {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session?.user?.email) return;

        const { data, error } = await supabase
            .from('user_roles')
            .select('role')
            .eq('email', session.user.email)
            .single();

        if (data && !error) {
            setCurrentUserRole(data.role); // 'admin' or 'super_admin'
        }
    };

    const fetchUsers = async () => {
        setIsLoading(true);
        try {
            const { data, error } = await supabase
                .from('user_roles')
                .select('*')
                .order('created_at', { ascending: false });

            if (error) throw error;
            setUsers(data || []);
        } catch (error) {
            console.error('Failed to fetch users:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const handleDeleteUser = async (targetEmail: string) => {
        if (!confirm(`Are you sure you want to remove ${targetEmail}?`)) return;

        try {
            // We can call the backend API we set up, OR directly use Supabase since we have the client here.
            // Using backend for extra security check if desired, but user request implies DB logic here is fine for UI.
            // Let's use the backend endpoint since we just built it to be secure,
            // BUT we need the current user's email to pass as 'requester_email'.

            const { data: { session } } = await supabase.auth.getSession();
            const requesterEmail = session?.user?.email;

            if (!requesterEmail) return;

            // Use centralized API client
            const response = await api.delete(`/admin/users?requester_email=${requesterEmail}&target_email=${targetEmail}`);

            if (!response.ok) {
                const err = await response.json();
                throw new Error(err.detail || 'Failed to delete');
            }

            // Remove from local state
            setUsers(prev => prev.filter(u => u.email !== targetEmail));

        } catch (err) {
            console.error(err);
            alert("Failed to remove user. Ensure you are a Super Admin.");
        }
    };

    const filteredUsers = users.filter(user =>
        user.email.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const isSuperAdmin = currentUserRole === 'super_admin';

    return (
        <div>
            {/* Header */}
            <header className="flex justify-between items-start mb-8">
                <div>
                    <div className="flex items-center gap-3 mb-1">
                        <h2 className="text-2xl font-bold text-foreground">Users Management</h2>
                        {!isSuperAdmin && currentUserRole && (
                            <div className="flex items-center gap-1 px-2 py-0.5 rounded-md bg-amber-500/10 border border-amber-500/20 text-amber-500 text-[10px] font-bold uppercase tracking-wider">
                                <Lock className="w-3 h-3" />
                                View Only
                            </div>
                        )}
                    </div>
                    <p className="text-muted-foreground">Manage user access, roles, and invitations.</p>
                </div>
                {isSuperAdmin && (
                    <button
                        onClick={() => setIsInviteModalOpen(true)}
                        className="flex items-center gap-2 px-4 py-2 bg-gradient-to-r from-yellow-500 to-amber-500 hover:from-yellow-400 hover:to-amber-400 text-white rounded-xl text-sm font-bold shadow-lg shadow-amber-500/20 transition-all"
                    >
                        <Plus className="w-4 h-4" />
                        Add New User
                    </button>
                )}
            </header>

            {/* Toolbar */}
            <div className="flex justify-between items-center mb-6 gap-4">
                <div className="flex items-center gap-2 flex-1 max-w-lg bg-card border border-border rounded-xl px-4 py-2.5 focus-within:border-primary/50 transition-colors">
                    <Search className="w-4 h-4 text-muted-foreground" />
                    <input
                        type="text"
                        placeholder="Search users by email..."
                        className="bg-transparent border-none outline-none text-sm w-full placeholder:text-muted-foreground/70 text-foreground"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>
            </div>

            {/* Users Table */}
            <div className="bg-card border border-border rounded-2xl overflow-hidden backdrop-blur-sm min-h-[400px]">
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm min-w-[600px]">
                        <thead className="bg-muted/50 border-b border-border text-muted-foreground uppercase tracking-wider text-xs font-semibold">
                            <tr>
                                <th className="px-6 py-4 whitespace-nowrap">User</th>
                                <th className="px-6 py-4 whitespace-nowrap">Role</th>
                                <th className="px-6 py-4 whitespace-nowrap">Status</th>
                                <th className="px-6 py-4 text-right whitespace-nowrap">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-border">
                            {isLoading ? (
                                <tr>
                                    <td colSpan={4} className="px-6 py-20 text-center text-muted-foreground">
                                        Loading users...
                                    </td>
                                </tr>
                            ) : filteredUsers.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="px-6 py-20 text-center text-muted-foreground">
                                        No users found.
                                    </td>
                                </tr>
                            ) : (
                                filteredUsers.map((user) => (
                                    <tr key={user.id || user.email} className="hover:bg-muted/50 transition-colors group">
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="flex items-center gap-3">
                                                <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold border ${user.role === 'super_admin'
                                                    ? 'bg-amber-500/10 text-amber-500 border-amber-500/20'
                                                    : 'bg-primary/10 text-primary border-primary/20'
                                                    }`}>
                                                    {user.email.charAt(0).toUpperCase()}
                                                </div>
                                                <span className="font-medium text-foreground">{user.email}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            {user.role === 'super_admin' ? (
                                                <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-bold bg-amber-500/10 text-amber-400 border border-amber-500/20 shadow-sm shadow-amber-500/10">
                                                    <ShieldAlert className="w-3 h-3" />
                                                    Super Admin
                                                </span>
                                            ) : (
                                                <span className="inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-bold bg-primary/10 text-primary border border-primary/20">
                                                    <Shield className="w-3 h-3" />
                                                    Admin
                                                </span>
                                            )}
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <span className="inline-flex items-center gap-1.5 text-xs font-medium text-primary">
                                                <div className="w-1.5 h-1.5 rounded-full bg-primary shadow-[0_0_8px_color-mix(in_srgb,var(--primary),transparent_50%)]" />
                                                Active
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 text-right whitespace-nowrap">
                                            {isSuperAdmin && user.role !== 'super_admin' ? (
                                                <button
                                                    onClick={() => handleDeleteUser(user.email)}
                                                    className="p-2 text-muted-foreground hover:text-destructive hover:bg-destructive/10 rounded-lg transition-colors"
                                                    title="Delete User"
                                                >
                                                    <Trash2 className="w-4 h-4" />
                                                </button>
                                            ) : (
                                                <span className="text-muted-foreground/30 cursor-not-allowed" title={user.role === 'super_admin' ? "Super Admins cannot be deleted" : "View Only"}>
                                                    <Trash2 className="w-4 h-4 opacity-50" />
                                                </span>
                                            )}
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Invite Modal */}
            <AnimatePresence>
                {isInviteModalOpen && (
                    <InviteModal
                        onClose={() => setIsInviteModalOpen(false)}
                        onSuccess={() => {
                            fetchUsers();
                            setIsInviteModalOpen(false);
                        }}
                    />
                )}
            </AnimatePresence>
        </div >
    );
}

function InviteModal({ onClose, onSuccess }: { onClose: () => void, onSuccess: () => void }) {
    const [email, setEmail] = useState('');
    const [role, setRole] = useState<'admin' | 'super_admin'>('admin');
    const [status, setStatus] = useState<'idle' | 'sending' | 'success' | 'error'>('idle');
    const [errorMsg, setErrorMsg] = useState('');

    const supabase = createBrowserClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
    );

    const handleInvite = async (e: React.FormEvent) => {
        e.preventDefault();
        setStatus('sending');
        setErrorMsg('');

        try {
            // Check if user already exists
            const { data: existing } = await supabase.from('user_roles').select('id').eq('email', email).single();
            if (existing) {
                throw new Error("User already exists in admin list.");
            }

            // Insert new user
            const { error } = await supabase.from('user_roles').insert([
                {
                    email,
                    role,
                    is_admin: true
                }
            ]);

            if (error) throw error;

            setStatus('success');
            setTimeout(() => {
                onSuccess();
            }, 1500);

        } catch (err: unknown) {
            console.error(err);
            setStatus('error');
            setErrorMsg(err instanceof Error ? err.message : "Failed to add user.");
        }
    };

    return (
        <motion.div
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm"
        >
            <motion.div
                initial={{ scale: 0.95, opacity: 0 }} animate={{ scale: 1, opacity: 1 }}
                className="w-full max-w-md bg-card border border-border rounded-2xl shadow-2xl p-6 relative"
            >
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-lg font-bold text-foreground">Add New User</h3>
                    <button onClick={onClose} className="text-muted-foreground hover:text-foreground"><X className="w-5 h-5" /></button>
                </div>

                {status === 'success' ? (
                    <div className="text-center py-8">
                        <div className="w-16 h-16 bg-green-500/20 rounded-full flex items-center justify-center mx-auto mb-4">
                            <Check className="w-8 h-8 text-green-400" />
                        </div>
                        <h4 className="text-lg font-bold text-foreground mb-2">User Added Successfully!</h4>
                        <p className="text-muted-foreground text-sm">{email} is now an {role === 'super_admin' ? 'Super Admin' : 'Admin'}.</p>
                    </div>
                ) : (
                    <form onSubmit={handleInvite} className="space-y-5">
                        <div className="space-y-2">
                            <label className="text-xs font-bold text-muted-foreground uppercase">Email Address</label>
                            <div className="flex items-center gap-2 bg-background border border-border rounded-xl px-4 py-3 focus-within:border-primary/50 transition-colors">
                                <Mail className="w-4 h-4 text-muted-foreground" />
                                <input
                                    type="email"
                                    required
                                    placeholder="colleague@pansgpt.site"
                                    className="bg-transparent border-none outline-none text-sm w-full text-foreground placeholder:text-muted-foreground/70"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-xs font-bold text-muted-foreground uppercase">Role Assignment</label>
                            <div className="grid grid-cols-2 gap-3">
                                <button
                                    type="button"
                                    onClick={() => setRole('admin')}
                                    className={`flex flex-col items-center gap-2 p-3 rounded-xl border transition-all ${role === 'admin'
                                        ? 'bg-primary/10 border-primary text-primary'
                                        : 'bg-muted/30 border-border text-muted-foreground hover:border-muted-foreground/50'
                                        }`}
                                >
                                    <Shield className="w-5 h-5" />
                                    <span className="text-xs font-bold">Admin</span>
                                </button>
                                <button
                                    type="button"
                                    onClick={() => setRole('super_admin')}
                                    className={`flex flex-col items-center gap-2 p-3 rounded-xl border transition-all ${role === 'super_admin'
                                        ? 'bg-amber-500/10 border-amber-500 text-amber-500'
                                        : 'bg-muted/30 border-border text-muted-foreground hover:border-muted-foreground/50'
                                        }`}
                                >
                                    <ShieldAlert className="w-5 h-5" />
                                    <span className="text-xs font-bold">Super Admin</span>
                                </button>
                            </div>
                        </div>

                        {errorMsg && (
                            <p className="text-red-400 text-xs text-center font-medium bg-red-500/10 py-2 rounded-lg">{errorMsg}</p>
                        )}

                        <div className="flex justify-end gap-3 pt-4">
                            <button type="button" onClick={onClose} className="px-4 py-2 rounded-lg text-sm font-medium text-muted-foreground hover:bg-muted">Cancel</button>
                            <button
                                type="submit"
                                disabled={status === 'sending'}
                                className="px-6 py-2 rounded-lg text-sm font-bold bg-primary text-primary-foreground hover:bg-primary/90 shadow-lg shadow-primary/20 disabled:opacity-50 transition-all"
                            >
                                {status === 'sending' ? 'Adding...' : 'Add User'}
                            </button>
                        </div>
                    </form>
                )}
            </motion.div>
        </motion.div>
    );
}

"use client";

import { useEffect, useState, use } from 'react';
import { supabase } from '@/lib/supabase';
import { ArrowLeft, ChevronLeft, ChevronRight } from 'lucide-react';
import Link from 'next/link';
import SlideRenderer, { SlideData } from '@/components/SlideRenderer';

interface DocumentPageProps {
    params: Promise<{
        id: string;
    }>;
}

// --- TYPE DEFINITIONS FOR JSON STRUCTURE ---
interface DocumentJSON {
    metadata?: {
        filename: string;
        subject: string;
        total_pages: number;
        processed_at: string;
    };
    pages: SlideData[];
}

interface DocumentRow {
    id: string;
    filename?: string;
    subject?: string;
    content: string;
}

export default function DocumentPage({ params }: DocumentPageProps) {
    const { id } = use(params);

    const [doc, setDoc] = useState<DocumentRow | null>(null);
    const [slides, setSlides] = useState<SlideData[]>([]);
    const [metadata, setMetadata] = useState<DocumentJSON['metadata'] | null>(null);
    const [loading, setLoading] = useState(true);
    const [parseError, setParseError] = useState<string | null>(null);

    // Flashcard State (for Desktop)
    const [currentSlide, setCurrentSlide] = useState(0);

    function nextSlide() {
        if (currentSlide < slides.length - 1) {
            setCurrentSlide((prev) => prev + 1);
        }
    }

    function prevSlide() {
        if (currentSlide > 0) {
            setCurrentSlide((prev) => prev - 1);
        }
    }

    // --- 1. FETCH & PARSE JSON ---
    useEffect(() => {
        const fetchDoc = async () => {
            const { data, error } = await supabase
                .from('documents')
                .select('*')
                .eq('id', id)
                .single();

            if (data) {
                setDoc(data);

                // Try to parse as JSON (Hybrid Layout format)
                try {
                    const parsed: DocumentJSON = JSON.parse(data.content);

                    if (parsed.pages && Array.isArray(parsed.pages)) {
                        setSlides(parsed.pages);
                        setMetadata(parsed.metadata || null);
                    } else {
                        // Fallback: Treat as single slide with raw content
                        setSlides([{
                            page_number: 1,
                            heading: data.filename || 'Document',
                            slots: { slot_1: data.content },
                        }]);
                    }
                } catch (e) {
                    // Legacy format: Create a single standard slide
                    setSlides([{
                        page_number: 1,
                        heading: data.filename?.replace('.pdf', '') || 'Document',
                        raw_text: [data.content],
                    }]);
                    setParseError("Legacy format - displaying as single page");
                }
            }
            setLoading(false);
        };

        fetchDoc();
    }, [id]);

    // --- 2. KEYBOARD NAVIGATION (Desktop Flashcard Mode) ---
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (slides.length === 0) return;

            if (e.key === 'ArrowRight' || e.key === ' ') {
                e.preventDefault();
                nextSlide();
            } else if (e.key === 'ArrowLeft') {
                e.preventDefault();
                prevSlide();
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, [currentSlide, slides.length]);

    // --- LOADING STATE ---
    if (loading) return (
        <div className="flex min-h-screen items-center justify-center bg-white">
            <div className="h-10 w-10 animate-spin rounded-full border-4 border-indigo-600 border-t-transparent"></div>
        </div>
    );

    if (!doc) return (
        <div className="flex min-h-screen items-center justify-center bg-white">
            <p className="text-gray-900">Document not found</p>
        </div>
    );

    if (slides.length === 0) return (
        <div className="flex min-h-screen items-center justify-center bg-white">
            <p className="text-gray-900">No content available</p>
        </div>
    );

    return (
        <div className="flex min-h-screen flex-col bg-white font-sans">

            {/* HEADER */}
            <header className="sticky top-0 z-30 flex items-center justify-between border-b border-gray-200 bg-white px-4 py-3 shadow-sm">
                <div className="flex items-center gap-3">
                    <Link href="/" className="rounded-full p-2 text-gray-500 hover:bg-gray-100 transition-colors">
                        <ArrowLeft className="h-5 w-5" />
                    </Link>
                    <div>
                        <h1 className="max-w-[200px] truncate text-sm font-bold text-gray-900 sm:max-w-md sm:text-base">
                            {metadata?.filename?.replace('.pdf', '') || doc.filename?.replace('.pdf', '') || 'Document'}
                        </h1>
                        <p className="text-xs text-gray-500">{metadata?.subject || doc.subject || 'General'}</p>
                    </div>
                </div>

                {/* Page count badge */}
                <div className="hidden sm:flex items-center gap-2">
                    {parseError && (
                        <span className="rounded-full bg-amber-100 px-2 py-1 text-xs text-amber-700">Legacy</span>
                    )}
                    <span className="rounded-full bg-gray-100 px-3 py-1 text-xs font-medium text-gray-600">
                        {slides.length} {slides.length === 1 ? 'page' : 'pages'}
                    </span>
                </div>
            </header>

            {/* --- MOBILE LAYOUT (Vertical Scroll Mode) --- */}
            <div className="block md:hidden">
                <main className="flex flex-col items-center p-4 bg-white">
                    {slides.map((slide, index) => (
                        <div key={index} className="mb-8 w-full max-w-3xl">
                            {/* Page Number Badge */}
                            <div className="mb-2 flex items-center gap-2 pl-2">
                                <span className="text-xs font-semibold uppercase tracking-wider text-gray-400">
                                    Page {slide.page_number || index + 1}
                                </span>
                            </div>

                            {/* Slide Card */}
                            <div className="overflow-hidden rounded-2xl bg-white shadow-lg ring-1 ring-gray-200">
                                <div className="min-h-[40vh] p-6">
                                    <SlideRenderer slide={slide} />
                                </div>
                            </div>
                        </div>
                    ))}

                    <div className="pb-10 pt-4 text-center text-sm text-gray-400">
                        End of Document
                    </div>
                </main>
            </div>

            {/* --- DESKTOP LAYOUT (Flashcard Mode) --- */}
            <div className="hidden min-h-[calc(100vh-64px)] w-full flex-col items-center justify-start p-8 md:flex bg-gray-50">

                {/* Slide Container with Fixed Min Height */}
                <div className="relative w-full max-w-5xl">
                    {/* Main Card - Fixed Min Height */}
                    <div className="min-h-[60vh] overflow-hidden rounded-2xl bg-white shadow-xl ring-1 ring-gray-200">
                        <div className="p-8 md:p-12">
                            <SlideRenderer slide={slides[currentSlide]} />
                        </div>
                    </div>
                </div>

                {/* Previous Button */}
                <button
                    onClick={prevSlide}
                    disabled={currentSlide === 0}
                    className="fixed left-4 top-1/2 -translate-y-1/2 rounded-full border border-gray-200 bg-white p-4 text-gray-700 shadow-lg transition-all hover:scale-110 hover:bg-gray-50 hover:text-indigo-600 disabled:pointer-events-none disabled:opacity-0"
                    aria-label="Previous page"
                >
                    <ChevronLeft className="h-8 w-8" />
                </button>

                {/* Next Button */}
                <button
                    onClick={nextSlide}
                    disabled={currentSlide === slides.length - 1}
                    className="fixed right-4 top-1/2 -translate-y-1/2 rounded-full border border-gray-200 bg-white p-4 text-gray-700 shadow-lg transition-all hover:scale-110 hover:bg-gray-50 hover:text-indigo-600 disabled:pointer-events-none disabled:opacity-0"
                    aria-label="Next page"
                >
                    <ChevronRight className="h-8 w-8" />
                </button>

                {/* Progress Badge */}
                <div className="fixed bottom-6 left-1/2 -translate-x-1/2 rounded-full bg-gray-900 px-6 py-2 text-sm font-medium text-white shadow-lg">
                    Page {currentSlide + 1} of {slides.length}
                </div>

            </div>

        </div>
    );
}

'use client';

import { createBrowserClient } from '@supabase/auth-helpers-nextjs';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Loader2, AlertCircle, CheckCircle2, ArrowRight, ArrowLeft } from 'lucide-react';
import AbstractCube from '@/components/AbstractCube';

const NIGERIAN_UNIVERSITIES = [
    "University of Lagos (UNILAG)",
    "Obafemi Awolowo University (OAU)",
    "University of Ibadan (UI)",
    "University of Benin (UNIBEN)",
    "Ahmadu Bello University (ABU)",
    "University of Nigeria, Nsukka (UNN)",
    "Lagos State University (LASU)",
    "Covenant University",
    "Usman Danfodiyo University (UDUS)",
    "Nnamdi Azikiwe University (UNIZIK)",
    "University of Jos (UNIJOS)",
    "University of Ilorin (UNILORIN)",
    "Other"
];

const LEVELS = ["100lvl", "200lvl", "300lvl", "400lvl", "500lvl", "600lvl (PharmD)"];

export default function AuthPage() {
    const supabase = createBrowserClient(
        process.env.NEXT_PUBLIC_SUPABASE_URL!,
        process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
    );
    const router = useRouter();

    const [isSignUp, setIsSignUp] = useState(false);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState<{ type: 'error' | 'success', text: string } | null>(null);

    // Signup Wizard State
    const [signupStep, setSignupStep] = useState(0); // 0: Name, 1: Uni, 2: Level, 3: Auth
    const [formData, setFormData] = useState({
        firstName: '',
        otherNames: '',
        university: '',
        level: '',
        email: '',
        password: ''
    });

    // Login State
    const [loginEmail, setLoginEmail] = useState('');
    const [loginPassword, setLoginPassword] = useState('');

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setMessage(null);
        try {
            const { error } = await supabase.auth.signInWithPassword({
                email: loginEmail,
                password: loginPassword,
            });
            if (error) throw error;
            router.push('/admin');
            router.refresh();
        } catch (error: unknown) {
            const errorMessage = error instanceof Error ? error.message : 'Login failed.';
            setMessage({ type: 'error', text: errorMessage });
        } finally {
            setLoading(false);
        }
    };

    const handleSignupSubmit = async () => {
        setLoading(true);
        setMessage(null);
        try {
            // 1. Create Auth User
            const { data, error: authError } = await supabase.auth.signUp({
                email: formData.email,
                password: formData.password,
                options: {
                    emailRedirectTo: `${window.location.origin}/auth/callback`,
                    // We still save full name here as backup/metadata
                    data: { full_name: `${formData.firstName} ${formData.otherNames}`.trim() }
                },
            });

            if (authError) throw authError;

            if (data.user) {
                // 2. Update Profile immediately
                const { error: profileError } = await supabase
                    .from('profiles')
                    .update({
                        first_name: formData.firstName,
                        other_names: formData.otherNames,
                        university: formData.university,
                        level: formData.level,
                        updated_at: new Date().toISOString()
                    })
                    .eq('id', data.user.id);

                if (profileError) {
                    // Non-blocking error log, user is created anyway
                    console.error("Profile update failed during signup", profileError);
                }
            }

            setMessage({ type: 'success', text: 'Account created! Check your email to confirm.' });

        } catch (error: unknown) {
            const errorMessage = error instanceof Error ? error.message : 'Sign up failed.';
            setMessage({ type: 'error', text: errorMessage });
        } finally {
            setLoading(false);
        }
    };

    const nextStep = () => {
        setSignupStep(prev => prev + 1);
        setMessage(null);
    }

