                            )}

                            {/* Step 1: University */}
                            {signupStep === 1 && (
                                <div className="space-y-4 animate-in slide-in-from-right duration-300">
                                    <div className="space-y-1.5">
                                        <label className="text-sm font-bold text-slate-700">University</label>
                                        <select
                                            autoFocus
